import React, { useEffect, useState } from "react";
import { Link } from "react-router-dom";
import PersonalAIMentor from "./PersonalAIMentor";
import "./UserProfile.css";



export default function UserProfile() {
  const [user, setUser] = useState(null);
  const [savedArticles, setSavedArticles] = useState([]);
  const [savedResults, setSavedResults] = useState([]);
  const [openResults, setOpenResults] = useState({});
  const [recommendedArticles, setRecommendedArticles] = useState([]);

  useEffect(() => {
    const token = localStorage.getItem("auth_token");
    if (token) {
      const payload = JSON.parse(atob(token.split(".")[1]));
      setUser(payload);
    }
    setSavedArticles(JSON.parse(localStorage.getItem("savedArticles")) || []);
    setSavedResults(JSON.parse(localStorage.getItem("savedResults")) || []);
  }, []);

  useEffect(() => {
    if (!savedResults.length) return;
    const lastType = savedResults[savedResults.length - 1];
    if (!lastType) return;

    fetch(`http://localhost:5000/api/articles?type=${lastType}`)
      .then(res => res.ok ? res.json() : [])
      .then(data => setRecommendedArticles(data || []))
      .catch(() => setRecommendedArticles([]));
  }, [savedResults]);

  const removeArticle = (slug) => {
    const updated = savedArticles.filter(a => a.slug !== slug);
    setSavedArticles(updated);
    localStorage.setItem("savedArticles", JSON.stringify(updated));
  };

  const removeResult = (result) => {
    const updated = savedResults.filter(r => r !== result);
    setSavedResults(updated);
    localStorage.setItem("savedResults", JSON.stringify(updated));
    setOpenResults(prev => ({ ...prev, [result]: false }));
  };

  if (!user) return null;

  return (
    <section className="profile-page">
      <div className="profile-left">
        <img
          src={user.photo ? user.photo.replace("http:", "https:") : "/images/default.png"}
          alt={user.email}
          className="profile-avatar"
          onError={(e) => (e.target.src = "/images/default.png")}
        />
        <span className="profile-email">{user.email}</span>
        <PersonalAIMentor userType={savedResults[savedResults.length - 1] || "DEFAULT"} />
      </div>

      {savedResults.length > 0 && (
        <div className="saved-results">
          {savedResults.map(result => (
            <div key={result} className="saved-result">
              <img src="/save1.png" alt="remove" className="remove-icon-result" onClick={() => removeResult(result)} />
              <img src={`/images/types/${result}.png`} width="180" alt={result} />
              <p className={`test-descript ${openResults[result] ? "open" : ""}`}>{typeDescriptions[result]}</p>
              <span className="toggle-desc" onClick={() => setOpenResults(prev => ({ ...prev, [result]: !prev[result] }))}>
                {openResults[result] ? "შეკეცვა" : "გახსნა"}
              </span>
            </div>
          ))}
        </div>
      )}

      <div className="saved-section">
        <h3>შენახული სტატიები</h3>
        <div className="saved-cards">
          {savedArticles.map(a => (
            <div key={a.slug} className="saved-card-container">
              <Link to={`/articles/${a.slug}`} className="saved-card">
                <img src={a.image ? `http://localhost:5000${a.image}` : "/images/default.png"} alt={a.title} className="saved-card-image" onError={(e) => (e.target.src="/images/default.png")} />
                <p className="saved-card-title">{a.title}</p>
              </Link>
              <img src="/save1.png" className="remove-icon-card" alt="remove" onClick={() => removeArticle(a.slug)} />
            </div>
          ))}
        </div>
      </div>

      {recommendedArticles.length > 0 && (
        <div className="profile-articles-sidebar">
          <h3 className="sidebar-title">შენთვის რეკომენდებული სტატიები</h3>
          {recommendedArticles.map(a => (
            <Link key={a.slug} to={`/articles/${a.slug}`} className="article-card">
              <img className="article-thumb" alt={a.title} src={a.image ? `http://localhost:5000${a.image}` : "/images/default.png"} />
              <div className="article-info">
                <b>{a.title}</b>
                <p>{a.excerpt}</p>
              </div>
            </Link>
          ))}
        </div>
      )}
    </section>
  );
}
